    public java.util.concurrent.CompletableFuture<Object> getFeesForAsset(Object symbol, Object side, Object amount2, Object price2, Object... optionalArgs)
    {
        final Object amount3 = amount2;
        final Object price3 = price2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object amount = amount3;
            Object price = price3;
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            amount = this.toRealSymbolAmount(symbol, amount);
            price = this.toRealSymbolPrice(symbol, price);
            final Object finalAmount = amount;
            final Object finalPrice = price;
            Object request = this.extend(new java.util.HashMap<String, Object>() {{
                put( "baseId", Helpers.GetValue(market, "baseId") );
                put( "quoteId", Helpers.GetValue(market, "quoteId") );
                put( "orderType", side );
                put( "amount", finalAmount );
                put( "price", finalPrice );
            }}, parameters);
            return (this.matcherPostMatcherOrderbookBaseIdQuoteIdCalculateFee(request)).join();
        });

    }

    public java.util.concurrent.CompletableFuture<Object> customCalculateFee(Object symbol, Object type, Object side, Object amount, Object price, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object takerOrMaker = Helpers.getArg(optionalArgs, 0, "taker");
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.getFeesForAsset(symbol, side, amount, price)).join();
            // {
            //     "base":{
            //        "feeAssetId":"WAVES",
            //        "matcherFee":"1000000"
            //     },
            //     "discount":{
            //        "feeAssetId":"EMAMLxDnv3xiz8RXg8Btj33jcEw3wLczL3JKYYmuubpc",
            //        "matcherFee":"4077612"
            //     }
            //  }
            Object isDiscountFee = this.safeBool(parameters, "isDiscountFee", false);
            Object mode = null;
            if (Helpers.isTrue(isDiscountFee))
            {
                mode = this.safeValue(response, "discount");
            } else
            {
                mode = this.safeValue(response, "base");
            }
            Object matcherFee = this.safeString(mode, "matcherFee");
            Object feeAssetId = this.safeString(mode, "feeAssetId");
            Object feeAsset = this.safeCurrencyCode(feeAssetId);
            Object adjustedMatcherFee = this.fromRealCurrencyAmount(feeAsset, matcherFee);
            Object amountAsString = this.numberToString(amount);
            Object priceAsString = this.numberToString(price);
            Object feeCost = this.feeToPrecision(symbol, this.parseNumber(adjustedMatcherFee));
            Object feeRate = Precise.stringDiv(adjustedMatcherFee, Precise.stringMul(amountAsString, priceAsString));
            return new java.util.HashMap<String, Object>() {{
                put( "type", takerOrMaker );
                put( "currency", feeAsset );
                put( "rate", WavesexchangeCore.this.parseNumber(feeRate) );
                put( "cost", WavesexchangeCore.this.parseNumber(feeCost) );
            }};
        });

    }

