    /**
     * @method
     * @name wavesexchange#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see https://api.wavesplatform.com/v0/docs/#/candles/getCandles
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] timestamp in ms of the latest candle to fetch
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "baseId", Helpers.GetValue(market, "baseId") );
                put( "quoteId", Helpers.GetValue(market, "quoteId") );
                put( "interval", WavesexchangeCore.this.safeString(WavesexchangeCore.this.timeframes, timeframe, timeframe) );
            }};
            Object allowedCandles = this.safeInteger(this.options, "allowedCandles", 1440);
            Object until = this.safeInteger(parameters, "until");
            Object untilIsDefined = !Helpers.isEqual(until, null);
            if (Helpers.isTrue(Helpers.isEqual(limit, null)))
            {
                limit = allowedCandles;
            }
            limit = Helpers.mathMin(allowedCandles, limit);
            Object duration = Helpers.multiply(this.parseTimeframe(timeframe), 1000);
            if (Helpers.isTrue(Helpers.isEqual(since, null)))
            {
                Object now = this.milliseconds();
                Object timeEnd = ((Helpers.isTrue(untilIsDefined))) ? until : now;
                Object durationRoundedTimestamp = Helpers.multiply(this.parseToInt(Helpers.divide(timeEnd, duration)), duration);
                Object delta = Helpers.multiply((Helpers.subtract(limit, 1)), duration);
                Object timeStart = Helpers.subtract(durationRoundedTimestamp, delta);
                Helpers.addElementToObject(request, "timeStart", String.valueOf(timeStart));
                if (Helpers.isTrue(untilIsDefined))
                {
                    Helpers.addElementToObject(request, "timeEnd", String.valueOf(until));
                }
            } else
            {
                Helpers.addElementToObject(request, "timeStart", String.valueOf(since));
                if (Helpers.isTrue(untilIsDefined))
                {
                    Helpers.addElementToObject(request, "timeEnd", String.valueOf(until));
                } else
                {
                    Object timeEnd = this.sum(since, Helpers.multiply(duration, limit));
                    Helpers.addElementToObject(request, "timeEnd", String.valueOf(timeEnd));
                }
            }
            parameters = this.omit(parameters, "until");
            Object response = (this.publicGetCandlesBaseIdQuoteId(this.extend(request, parameters))).join();
            //
            //     {
            //         "__type": "list",
            //         "data": [
            //             {
            //                 "__type": "candle",
            //                 "data": {
            //                     "time": "2020-06-09T14:47:00.000Z",
            //                     "open": 0.0250385,
            //                     "close": 0.0250385,
            //                     "high": 0.0250385,
            //                     "low": 0.0250385,
            //                     "volume": 0.01033012,
            //                     "quoteVolume": 0.00025865,
            //                     "weightedAveragePrice": 0.0250385,
            //                     "maxHeight": 2099399,
            //                     "txsCount": 5,
            //                     "timeClose": "2020-06-09T14:47:59.999Z"
            //                 }
            //             }
            //         ]
            //     }
            //
            Object data = this.safeValue(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object result = this.parseOHLCVs(data, market, timeframe, since, limit);
            result = this.filterFutureCandles(result);
            Object lastClose = null;
            Object length = Helpers.getArrayLength(result);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(result)); i++)
            {
                Object j = Helpers.subtract(Helpers.subtract(length, i), 1);
                Object entry = Helpers.GetValue(result, j);
                Object open = Helpers.GetValue(entry, 1);
                if (Helpers.isTrue(Helpers.isEqual(open, null)))
                {
                    Helpers.addElementToObject(entry, 1, lastClose);
                    Helpers.addElementToObject(entry, 2, lastClose);
                    Helpers.addElementToObject(entry, 3, lastClose);
                    Helpers.addElementToObject(entry, 4, lastClose);
                    Helpers.addElementToObject(result, j, entry);
                }
                lastClose = Helpers.GetValue(entry, 4);
            }
            return result;
        });

    }

    public Object filterFutureCandles(Object ohlcvs)
    {
        Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        Object timestamp = this.milliseconds();
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(ohlcvs)); i++)
        {
            if (Helpers.isTrue(Helpers.isGreaterThan(Helpers.GetValue(Helpers.GetValue(ohlcvs, i), 0), timestamp)))
            {
                // stop when getting data from the future
                break;
            }
            ((java.util.List<Object>)result).add(Helpers.GetValue(ohlcvs, i));
        }
        return result;
    }

    public Object parseOHLCV(Object ohlcv, Object... optionalArgs)
    {
        //
        //     {
        //         "__type": "candle",
        //         "data": {
        //             "time": "2020-06-05T20:46:00.000Z",
        //             "open": 240.573975,
        //             "close": 240.573975,
        //             "high": 240.573975,
        //             "low": 240.573975,
        //             "volume": 0.01278413,
        //             "quoteVolume": 3.075528,
        //             "weightedAveragePrice": 240.573975,
        //             "maxHeight": 2093895,
        //             "txsCount": 5,
        //             "timeClose": "2020-06-05T20:46:59.999Z"
        //         }
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object data = this.safeValue(ohlcv, "data", new java.util.HashMap<String, Object>() {{}});
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.parse8601(this.safeString(data, "time")), this.safeNumber(data, "open"), this.safeNumber(data, "high"), this.safeNumber(data, "low"), this.safeNumber(data, "close"), this.safeNumber(data, "volume", 0)));
    }

