            Object amountAsset = this.getAssetId(Helpers.GetValue(market, "baseId"));
            Object priceAsset = this.getAssetId(Helpers.GetValue(market, "quoteId"));
            Object isMarketOrder = (Helpers.isEqual(type, "market"));
            Object triggerPrice = this.safeFloat2(parameters, "triggerPrice", "stopPrice");
            Object isStopOrder = (!Helpers.isEqual(triggerPrice, null));
            if (Helpers.isTrue(Helpers.isTrue((isMarketOrder)) && Helpers.isTrue((Helpers.isEqual(price, null)))))
            {
                throw new InvalidOrder((String)Helpers.add(Helpers.add(Helpers.add(this.id, " createOrder() requires a price argument for "), type), " orders to determine the max price for buy and the min price for sell")) ;
            }
            Object timestamp = this.milliseconds();
