            var defaultExpiryDeltaparametersVariable = this.handleOptionAndParams(parameters, "createOrder", "defaultExpiry", this.safeInteger(this.options, "createOrderDefaultExpiry", 2419200000L));
            defaultExpiryDelta = ((java.util.List<Object>) defaultExpiryDeltaparametersVariable).get(0);
            parameters = ((java.util.List<Object>) defaultExpiryDeltaparametersVariable).get(1);
            Object expiration = this.sum(timestamp, defaultExpiryDelta);
            Object matcherFees = (this.getFeesForAsset(symbol, side, amount, price)).join();
            // {
            //     "base":{
            //        "feeAssetId":"WAVES", // varies depending on the trading pair
            //        "matcherFee":"1000000"
            //     },
            //     "discount":{
            //        "feeAssetId":"EMAMLxDnv3xiz8RXg8Btj33jcEw3wLczL3JKYYmuubpc",
