    public Object parseOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "Cancelled", "canceled" );
            put( "Accepted", "open" );
            put( "Filled", "closed" );
            put( "PartiallyFilled", "open" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object getSymbolFromAssetPair(Object assetPair)
    {
        // a blank string or null can indicate WAVES
        Object baseId = this.safeString(assetPair, "amountAsset", "WAVES");
        Object quoteId = this.safeString(assetPair, "priceAsset", "WAVES");
        return Helpers.add(Helpers.add(this.safeCurrencyCode(baseId), "/"), this.safeCurrencyCode(quoteId));
    }

    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // createOrder
        //
        //     {
        //         "version": 4,
        //         "id": "BshyeHXDfJmTnjTdBYt371jD4yWaT3JTP6KpjpsiZepS",
        //         "sender": "3P8VzLSa23EW5CVckHbV7d5BoN75fF1hhFH",
        //         "senderPublicKey": "AHXn8nBA4SfLQF7hLQiSn16kxyehjizBGW1TdrmSZ1gF",
        //         "matcherPublicKey": "9cpfKN9suPNvfeUNphzxXMjcnn974eme8ZhWUjaktzU5",
        //         "assetPair": {
        //             "amountAsset": "474jTeYx2r2Va35794tCScAXWJG9hU2HcgxzMowaZUnu",
        //             "priceAsset": "DG2xFkPdDwKUoBkzGAhQtLpSGzfXLiCYPEzeKH2Ad24p",
        //         },
        //         "orderType": "buy",
        //         "amount": 10000,
        //         "price": 400000000,
        //         "timestamp": 1599848586891,
        //         "expiration": 1602267786891,
        //         "matcherFee": 3008,
        //         "matcherFeeAssetId": "474jTeYx2r2Va35794tCScAXWJG9hU2HcgxzMowaZUnu",
        //         "signature": "3D2h8ubrhuWkXbVn4qJ3dvjmZQxLoRNfjTqb9uNpnLxUuwm4fGW2qGH6yKFe2SQPrcbgkS3bDVe7SNtMuatEJ7qy",
        //         "proofs": [
        //             "3D2h8ubrhuWkXbVn4qJ3dvjmZQxLoRNfjTqb9uNpnLxUuwm4fGW2qGH6yKFe2SQPrcbgkS3bDVe7SNtMuatEJ7qy",
        //         ],
        //         "attachment":"77rnoyFX5BDr15hqZiUtgXKSN46zsbHHQjVNrTMLZcLz62mmFKr39FJ"
        //     }
        //
        //
        // fetchOrder, fetchOrders, fetchOpenOrders, fetchClosedOrders
        //
        //     {
        //         "id": "81D9uKk2NfmZzfG7uaJsDtxqWFbJXZmjYvrL88h15fk8",
        //         "type": "buy",
        //         "orderType": "limit",
        //         "amount": 30000000000,
        //         "filled": 0,
        //         "price": 1000000,
        //         "fee": 300000,
        //         "filledFee": 0,
        //         "feeAsset": "WAVES",
        //         "timestamp": 1594303779322,
        //         "status": "Cancelled",
        //         "assetPair": {
        //             "amountAsset": "474jTeYx2r2Va35794tCScAXWJG9hU2HcgxzMowaZUnu",
        //             "priceAsset": "WAVES"
        //         },
        //         "avgWeighedPrice": 0,
        //         "version": 4,
        //         "totalExecutedPriceAssets": 0,  // in fetchOpenOrder/s
        //         "attachment":"77rnoyFX5BDr15hqZiUtgXKSN46zsbHHQjVNrTMLZcLz62mmFKr39FJ"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(order, "timestamp");
        Object side = this.safeString2(order, "type", "orderType");
        Object type = "limit";
        if (Helpers.isTrue(Helpers.inOp(order, "type")))
        {
            // fetchOrders
            type = this.safeString(order, "orderType", type);
        }
        Object id = this.safeString(order, "id");
        Object filledString = this.safeString(order, "filled");
        Object priceString = this.safeString(order, "price");
        Object amountString = this.safeString(order, "amount");
        Object assetPair = this.safeValue(order, "assetPair");
        Object symbol = null;
        if (Helpers.isTrue(!Helpers.isEqual(assetPair, null)))
        {
            symbol = this.getSymbolFromAssetPair(assetPair);
        } else if (Helpers.isTrue(!Helpers.isEqual(market, null)))
        {
            symbol = Helpers.GetValue(market, "symbol");
        }
        Object amountCurrency = this.safeCurrencyCode(this.safeString(assetPair, "amountAsset", "WAVES"));
        Object price = this.fromRealSymbolPrice(symbol, priceString);
        Object amount = this.fromRealCurrencyAmount(amountCurrency, amountString);
        Object filled = this.fromRealCurrencyAmount(amountCurrency, filledString);
        Object average = this.fromRealSymbolPrice(symbol, this.safeString(order, "avgWeighedPrice"));
        Object status = this.parseOrderStatus(this.safeString(order, "status"));
        Object fee = null;
        if (Helpers.isTrue(Helpers.inOp(order, "type")))
        {
            Object code = this.safeCurrencyCode(this.safeString(order, "feeAsset"));
            fee = new java.util.HashMap<String, Object>() {{
                put( "currency", code );
                put( "fee", WavesexchangeCore.this.parseNumber(WavesexchangeCore.this.fromRealCurrencyAmount(code, WavesexchangeCore.this.safeString(order, "filledFee"))) );
            }};
        } else
        {
            Object code = this.safeCurrencyCode(this.safeString(order, "matcherFeeAssetId", "WAVES"));
            fee = new java.util.HashMap<String, Object>() {{
                put( "currency", code );
                put( "fee", WavesexchangeCore.this.parseNumber(WavesexchangeCore.this.fromRealCurrencyAmount(code, WavesexchangeCore.this.safeString(order, "matcherFee"))) );
            }};
        }
        Object triggerPrice = null;
        Object attachment = this.safeString(order, "attachment");
        if (Helpers.isTrue(!Helpers.isEqual(attachment, null)))
        {
            Object decodedAttachment = this.parseJson(this.decode(this.base58ToBinary(attachment)));
            if (Helpers.isTrue(!Helpers.isEqual(decodedAttachment, null)))
            {
                Object c = this.safeValue(decodedAttachment, "c");
                if (Helpers.isTrue(!Helpers.isEqual(c, null)))
                {
                    Object v = this.safeValue(c, "v");
                    if (Helpers.isTrue(!Helpers.isEqual(v, null)))
                    {
                        triggerPrice = this.safeString(v, "p");
                    }
                }
            }
        }
        final Object finalSymbol = symbol;
        final Object finalType = type;
        final Object finalTriggerPrice = triggerPrice;
        final Object finalFee = fee;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "id", id );
            put( "clientOrderId", null );
            put( "timestamp", timestamp );
            put( "datetime", WavesexchangeCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "symbol", finalSymbol );
            put( "type", finalType );
            put( "timeInForce", null );
            put( "postOnly", null );
            put( "side", side );
            put( "price", price );
            put( "triggerPrice", finalTriggerPrice );
            put( "amount", amount );
            put( "cost", null );
            put( "average", average );
            put( "filled", filled );
            put( "remaining", null );
            put( "status", status );
            put( "fee", finalFee );
            put( "trades", null );
        }}, market);
    }

    public java.util.concurrent.CompletableFuture<Object> getWavesAddress()
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object cachedAddreess = this.safeString(this.options, "wavesAddress");
            if (Helpers.isTrue(Helpers.isEqual(cachedAddreess, null)))
            {
                Object request = new java.util.HashMap<String, Object>() {{
                    put( "publicKey", WavesexchangeCore.this.apiKey );
                }};
                Object response = (this.nodeGetAddressesPublicKeyPublicKey(request)).join();
                Helpers.addElementToObject(this.options, "wavesAddress", this.safeString(response, "address"));
                return Helpers.GetValue(this.options, "wavesAddress");
            } else
            {
                return cachedAddreess;
            }
        });

    }

    /**
     * @method
     * @name wavesexchange#fetchBalance
     * @description query for balance and get the amount of funds available for trading or funds locked in orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [balance structure]{@link https://docs.ccxt.com/?id=balance-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchBalance(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // makes a lot of different requests to get all the data
            // in particular:
            // fetchMarkets, getWavesAddress,
            // getTotalBalance (doesn't include waves), getReservedBalance (doesn't include waves)
            // getReservedBalance (includes WAVES)
            // I couldn't find another way to get all the data
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            this.checkRequiredDependencies();
            this.checkRequiredKeys();
            (this.loadMarkets()).join();
            Object wavesAddress = (this.getWavesAddress()).join();
            Object request = new java.util.HashMap<String, Object>() {{
                put( "address", wavesAddress );
            }};
            Object totalBalance = (this.nodeGetAssetsBalanceAddress(request)).join();
            // {
            //   "address": "3P8VzLSa23EW5CVckHbV7d5BoN75fF1hhFH",
            //   "balances": [
            //     {
            //       "assetId": "DG2xFkPdDwKUoBkzGAhQtLpSGzfXLiCYPEzeKH2Ad24p",
            //       "balance": 1177200,
            //       "reissuable": false,
            //       "minSponsoredAssetFee": 7420,
            //       "sponsorBalance": 47492147189709,
            //       "quantity": 999999999775381400,
            //       "issueTransaction": {
            //         "senderPublicKey": "BRnVwSVctnV8pge5vRpsJdWnkjWEJspFb6QvrmZvu3Ht",
            //         "quantity": 1000000000000000000,
            //         "fee": 100400000,
            //         "description": "Neutrino USD",
            //         "type": 3,
            //         "version": 2,
            //         "reissuable": false,
            //         "script": null,
            //         "sender": "3PC9BfRwJWWiw9AREE2B3eWzCks3CYtg4yo",
            //         "feeAssetId": null,
            //         "chainId": 87,
            //         "proofs": [
            //           "3HNpbVkgP69NWSeb9hGYauiQDaXrRXh3tXFzNsGwsAAXnFrA29SYGbLtziW9JLpXEq7qW1uytv5Fnm5XTUMB2BxU"
            //         ],
            //         "assetId": "DG2xFkPdDwKUoBkzGAhQtLpSGzfXLiCYPEzeKH2Ad24p",
            //         "decimals": 6,
            //         "name": "USD-N",
            //         "id": "DG2xFkPdDwKUoBkzGAhQtLpSGzfXLiCYPEzeKH2Ad24p",
            //         "timestamp": 1574429393962
            //       }
            //     }
            //   ]
            // }
            Object balances = this.safeValue(totalBalance, "balances", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object result = new java.util.HashMap<String, Object>() {{}};
            Object timestamp = null;
            Object assetIds = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object nonStandardBalances = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(balances)); i++)
            {
                Object entry = Helpers.GetValue(balances, i);
                Object entryTimestamp = this.safeInteger(entry, "timestamp");
                timestamp = ((Helpers.isTrue((Helpers.isEqual(timestamp, null))))) ? entryTimestamp : Helpers.mathMax(timestamp, entryTimestamp);
                Object issueTransaction = this.safeValue(entry, "issueTransaction");
                Object currencyId = this.safeString(entry, "assetId");
                Object balance = this.safeString(entry, "balance");
                Object currencyExists = (Helpers.inOp(this.currencies_by_id, currencyId));
                if (Helpers.isTrue(currencyExists))
                {
                    Object code = this.safeCurrencyCode(currencyId);
                    Helpers.addElementToObject(result, code, this.account());
                    Helpers.addElementToObject(Helpers.GetValue(result, code), "total", this.fromRealCurrencyAmount(code, balance));
                } else if (Helpers.isTrue(Helpers.isEqual(issueTransaction, null)))
                {
                    ((java.util.List<Object>)assetIds).add(currencyId);
                    ((java.util.List<Object>)nonStandardBalances).add(balance);
                }
            }
            Object nonStandardAssets = Helpers.getArrayLength(assetIds);
            if (Helpers.isTrue(nonStandardAssets))
            {
                Object requestInner = new java.util.HashMap<String, Object>() {{
                    put( "ids", assetIds );
                }};
                Object response = (this.publicGetAssets(requestInner)).join();
                Object data = this.safeValue(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
                {
                    Object entry = Helpers.GetValue(data, i);
                    Object balance = Helpers.GetValue(nonStandardBalances, i);
                    Object inner = this.safeValue(entry, "data");
                    Object precision = this.parsePrecision(this.safeString(inner, "precision"));
                    Object ticker = this.safeString(inner, "ticker");
                    Object code = this.safeCurrencyCode(ticker);
                    Helpers.addElementToObject(result, code, this.account());
                    Helpers.addElementToObject(Helpers.GetValue(result, code), "total", Precise.stringMul(balance, precision));
                }
            }
            Object currentTimestamp = this.milliseconds();
            Object byteArray = new java.util.ArrayList<Object>(java.util.Arrays.asList(this.base58ToBinary(this.apiKey), this.numberToBE(currentTimestamp, 8)));
            Object binary = this.binaryConcatArray(byteArray);
            Object hexSecret = this.binaryToBase16(this.base58ToBinary(this.secret));
            Object signature = this.axolotl(this.binaryToBase16(binary), hexSecret, ed25519());
            Object matcherRequest = new java.util.HashMap<String, Object>() {{
                put( "publicKey", WavesexchangeCore.this.apiKey );
                put( "signature", signature );
                put( "timestamp", String.valueOf(currentTimestamp) );
            }};
            Object reservedBalance = (this.matcherGetMatcherBalanceReservedPublicKey(matcherRequest)).join();
            // { WAVES: 200300000 }
            Object reservedKeys = Helpers.objectKeys(reservedBalance);
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(reservedKeys)); i++)
            {
                Object currencyId = Helpers.GetValue(reservedKeys, i);
                Object code = this.safeCurrencyCode(currencyId);
                if (!Helpers.isTrue((Helpers.inOp(result, code))))
                {
                    Helpers.addElementToObject(result, code, this.account());
                }
                Object amount = this.safeString(reservedBalance, currencyId);
                Helpers.addElementToObject(Helpers.GetValue(result, code), "used", this.fromRealCurrencyAmount(code, amount));
            }
            Object wavesRequest = new java.util.HashMap<String, Object>() {{
                put( "address", wavesAddress );
            }};
            Object wavesTotal = (this.nodeGetAddressesBalanceAddress(wavesRequest)).join();
            // {
            //   "address": "3P8VzLSa23EW5CVckHbV7d5BoN75fF1hhFH",
            //   "confirmations": 0,
            //   "balance": 909085978
            // }
            Helpers.addElementToObject(result, "WAVES", this.safeValue(result, "WAVES", this.account()));
            Helpers.addElementToObject(Helpers.GetValue(result, "WAVES"), "total", this.fromRealCurrencyAmount("WAVES", this.safeString(wavesTotal, "balance")));
            result = this.setUndefinedBalancesToZero(result);
            Helpers.addElementToObject(result, "timestamp", timestamp);
            Helpers.addElementToObject(result, "datetime", this.iso8601(timestamp));
            return this.safeBalance(result);
        });

    }

    public Object setUndefinedBalancesToZero(Object balances, Object... optionalArgs)
    {
        Object key = Helpers.getArg(optionalArgs, 0, "used");
        Object codes = Helpers.objectKeys(balances);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(codes)); i++)
        {
            Object code = Helpers.GetValue(codes, i);
            if (Helpers.isTrue(Helpers.isEqual(this.safeValue(Helpers.GetValue(balances, code), "used"), null)))
            {
                Helpers.addElementToObject(Helpers.GetValue(balances, code), key, "0");
            }
        }
        return balances;
    }

